    fn sample_claims() -> Claims {
        let now = now_secs();
        Claims {
            sub: "test-user-001".to_string(),
            exp: now + 3600,
            iat: now,
            iss: Some("test-issuer".to_string()),
            aud: Some("test-audience".to_string()),
            roles: Some(vec!["admin".to_string()]),
            email: Some("test@example.com".to_string()),
            name: Some("Test User".to_string()),
        }
    }

    fn default_verifier() -> JwtVerifier {
        JwtVerifier::new("test-secret-key-long-enough-for-hmac", Algorithm::HS256)
            .with_issuer("test-issuer")
            .with_audience("test-audience")
    }

    #[test]
    fn test_verify_valid_token_hs256() {
        let secret = "test-secret-key-long-enough-for-hmac";
        let verifier = default_verifier();
        let claims = sample_claims();
        let token = create_test_token(secret, Algorithm::HS256, &claims).unwrap();
        let user = verifier.verify_and_extract_user(&token).unwrap();
        assert_eq!(user.user_id, "test-user-001");
        assert_eq!(user.email, Some("test@example.com".to_string()));
        assert_eq!(user.name, Some("Test User".to_string()));
        assert_eq!(user.roles, vec!["admin".to_string()]);
    }

